((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1400 (M98)', '3HAC 2914-1', 'Lubricación', 'Brackets resorte equilibrado', 'c/4.000h ó 1 año', NULL, '4 puntos de lubricación (sobre y bajo los 2 resortes). Grasa: Optimol PDO (3HAA 1001-294)'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1400 (M98)', '3HAC 2914-1', 'Reemplazo', 'Batería sistema medida (NiCd)', '3 años', NULL, 'NiCd art. 4944 026-4. Alternativa litio: 3-cell 3HAB 9999-1 (hasta 5 años) ó 6-cell 3HAB 9999-2 (hasta 5 años)'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1400 (M98)', '3HAC 2914-1', 'Inspección', 'Tope mecánico eje 1 + Cableado', 'c/2.000h ó 6 meses', NULL, 'Tope: verificar que pin no esté doblado. Cableado: inspeccionar todo visible, sustituir si dañado'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1400 (M2000/M2004)', '3HAC021111-001', 'Cambio aceite', 'Reductoras ejes 1-4', 'Lubricated for life', NULL, 'Gearboxes sin cambio programado. Aceite: Mobil Gear 600 XP 320 (art. 1171 2016-604). Vol: eje1 2L (susp:2.7L), ejes2-3 1.7L, eje4 30ml'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1400 (M2000/M2004)', '3HAC021111-001', 'Engrase', 'Muñeca ejes 5-6', 'c/4.000h ó 1 año', NULL, '2 ml por cada uno de los 3 nipples. Grasa: Shell Alvania WR2 (3HAB 3537-1)'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1400 (M2000/M2004)', '3HAC021111-001', 'Lubricación', 'Brackets resorte equilibrado', 'c/4.000h ó 1 año', NULL, '4 puntos de lubricación. Grasa: Optimol PDO (3HAA 1001-294)'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1400 (M2000/M2004)', '3HAC021111-001', 'Reemplazo', 'Batería sistema medida (NiCd)', '3 años', NULL, 'NiCd art. 4944 026-4. Alternativa litio: 3-cell 3HAB 9999-1 (hasta 5 años) ó 6-cell 3HAB 9999-2 (hasta 5 años)'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1400 (M2000/M2004)', '3HAC021111-001', 'Inspección', 'Tope mecánico eje 1 + Cableado', 'c/2.000h ó 6 meses', NULL, 'Tope: verificar que pin no esté doblado (ref 3HAB 3258-1). Cableado: inspeccionar todo visible, sustituir si dañado'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7600 (Gen.1)', '3HAC022033-001', 'Cambio aceite', 'Reductoras ejes 1-3', 'c/12.000h', NULL, 'Gen.1: S/N M2000 76-20000-26999 / M2000A 76-30000-33999 / M2004 76-50000-50999. Aceite ejes 1-3: Optimol Optigear RMO150 (reemplazado por Castrol Optigear RO150). Eje4 sec/5sec: Mobilgear 600 XP 320. Eje4 pri/5pri/6: Shell Tivela S150 (=Shell Omala S4 WE150). ATENCIÓN: 3 tipos de aceite distintos, NO mezclar entre grupos.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7600 (Gen.1)', '3HAC022033-001', 'Cambio aceite', 'Reductora eje 4 secundaria', 'c/12.000h', NULL, 'Gen.1 eje 4 secundario: Mobilgear 600 XP 320 (~4L). Eje 4 primario (todos): Shell Tivela S150 / Kyodo Yushi TMO150 (~1L).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7600 (Gen.1)', '3HAC022033-001', 'Cambio aceite', 'Reductora eje 5 secundaria', 'c/12.000h', NULL, 'Gen.1 eje 5 secundario: Mobilgear 600 XP 320 (~4L). Eje 5 primario (todos): Shell Tivela S150 / Kyodo Yushi TMO150 (~0.7L).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7600 (Gen.1)', '3HAC022033-001', 'Cambio aceite', 'Reductoras ejes 4-5 primarias + eje 6', '1er:6.000h, 2do:24.000h, +c/24.000h', NULL, 'Eje 4 primario ~1L, eje 5 primario ~0.7L, eje 6 ~0.7L. Gen.1: Shell Tivela S150 (=Shell Omala S4 WE150). Mismo schedule en todas las generaciones para estos ejes.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7600 (Gen.2/3)', '3HAC022033-001', 'Cambio aceite', 'Reductoras ejes 1-3', '1er:6.000h, 2do:24.000h, +c/24.000h', NULL, 'Gen.2: S/N M2000 76-27000+ / M2000A 76-34000+ / M2004 76-51000+. Aceite ejes 1-2: Shell Tivela S150. Gen.3: S/N igual pero entregados después Oct-2008. Todos los ejes: Kyodo Yushi TMO150. Volúmenes: eje1 ~7.5L, eje2 ~5L, eje3 ~4L. NO mezclar TMO150 con Optigear RMO150/Castrol RO150.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7600 (Gen.2/3)', '3HAC022033-001', 'Cambio aceite', 'Reductora eje 4 secundaria', '1er:6.000h, 2do:24.000h, +c/24.000h', NULL, 'Gen.2/3 eje 4 secundario: Kyodo Yushi TMO150 (~4L). Gen.2 eje 4 secundario: puede ser Shell Tivela S150 — verificar etiqueta en robot.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7600 (Gen.2/3)', '3HAC022033-001', 'Cambio aceite', 'Reductora eje 5 secundaria', '1er:6.000h, 2do:24.000h, +c/24.000h', NULL, 'Gen.2/3 eje 5 secundario: Kyodo Yushi TMO150 (~4L). Gen.2: puede ser Shell Tivela S150 — verificar etiqueta en robot.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7600 (Gen.2/3)', '3HAC022033-001', 'Cambio aceite', 'Reductoras ejes 4-5 primarias + eje 6', '1er:6.000h, 2do:24.000h, +c/24.000h', NULL, 'Gen.3 (y Gen.2 post-SI10177): todos los ejes Kyodo Yushi TMO150. Eje 4 primario ~1L, eje 5 primario ~0.7L, eje 6 ~0.7L.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7600', '3HAC022033-001', 'Lubricación', 'Rodamientos disp. equilibrado', 'c/12.000h', NULL, 'Siempre lubricar rodamiento frontal tras recolocar eje del dispositivo equilibrado.');
