((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7600', '3HAC022033-001', 'Inspección', 'Sello motor (Type B motors)', 'c/12 meses', NULL, 'Solo válido para robots con motores Type B (evacuación en brida). Ver sección Type A vs Type B motors.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7600', '3HAC022033-001', 'Inspección', 'Arnés cables / Etiquetas / Amortiguadores / Topes mecánicos', 'c/12 meses', NULL, 'Arnés: reemplazar si daño o grietas o próximo a vida útil (40.000h uso normal, 20.000h uso extremo).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7600', '3HAC022033-001', 'Reemplazo', 'Batería SMB (3-pole RMU101/102)', '36 meses ó alerta baja', NULL, NULL),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7600', '3HAC022033-001', 'Reemplazo', 'Batería SMB (2-pole DSQC633A)', 'Alerta baja', NULL, 'Vida típica 36m (2d/sem off) ó 18m (16h/d off).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7600', '3HAC022033-001', 'Overhaul', 'Robot completo', '40.000h', NULL, NULL),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 340 (M98)', '3HAC 4760-1', 'Engrase', 'Eje telescópico eje 4 (cojinetes)', 'c/500h', 'Solo IRB340r/SA/SAS', 'Mobilgrease FM102 / Optimol Obeen UF2, 1.3 ml. Verificar también apriete de tornillos de fijación.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 340 (M98)', '3HAC 4760-1', 'Engrase', 'Sistema de barras (anillos desgaste)', 'c/500h ó 1 año', NULL, 'Mobilgrease FM102 / Optimol Obeen UF2, 0.5 ml. Escuchar chirridos. Distancia holder normal: 126mm (reemplazar si <124mm).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 340 (M98)', '3HAC 4760-1', 'Inspección', 'Sist. vacío (filtro + pinzas manguito)', 'c/500h', 'Solo si opción vacío', 'Vaciar filtro aire 3HAC 3718-1. Verificar posición pinzas (150mm desde juntas). Cambio válvulas neumáticas c/4.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 340 (M98)', '3HAC 4760-1', 'Inspección', 'Gearboxes ejes 1-3 (backlash)', 'c/4.000h ó 2 años', NULL, 'Holgura en ejes de salida < ±0.0167° (1 minuto de arco). Si excesiva → llamar servicio.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 340 (M98)', '3HAC 4760-1', 'Cambio aceite', 'Gearboxes ejes 1-3', 'Primer cambio: 12.000h ó 3 años', NULL, 'SOLO el primer cambio a 12.000h. Aceite: Mobil DTE FM 220. Volumen: 0.9L por gearbox (x3 = 2.7L total). Recalibrar ejes 1-3 tras cambio (método 2).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 340 (M98)', '3HAC 4760-1', 'Reemplazo', 'Batería SMB (NiCd)', '3 años', NULL, 'NiCd art. 4944 026-4. Alternativa litio: 3-cell 3HAB 9999-1 (hasta 5 años) ó 6-cell 3HAB 9999-2.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 340 (M98)', '3HAC 4760-1', 'Inspección', 'Ventilador manipulador (rodamientos)', 'c/30.000h ó 5 años', NULL, NULL),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 340 (M2004)', '3HAC022546-001', 'Engrase', 'Eje telescópico eje 4 (cojinetes)', 'c/500h', 'Solo IRB340r/SA/SAS', 'Mobilgrease FM102 / Optimol Obeen UF2, 1.3 ml. Verificar apriete tornillos set screws.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 340 (M2004)', '3HAC022546-001', 'Engrase', 'Sistema de barras (anillos desgaste)', 'c/500h ó 1 año', NULL, 'Mobilgrease FM102 / Optimol Obeen UF2, 0.5 ml. Distancia holder normal: 126mm (reemplazar si <124mm).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 340 (M2004)', '3HAC022546-001', 'Inspección', 'Sist. vacío (filtro + pinzas manguito)', 'c/500h', 'Solo si opción vacío', 'Vaciar filtro 3HAC 3718-1. Cambio válvulas neumáticas c/4.000h (vida: 4×10⁷ ciclos). Art. unidad válvulas: 3HAC 8030-4 PIAB.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 340 (M2004)', '3HAC022546-001', 'Inspección', 'Gearboxes ejes 1-3 (backlash)', 'c/4.000h ó 2 años', NULL, 'Holgura en ejes de salida < ±0.0167° (1 minuto de arco).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 340 (M2004)', '3HAC022546-001', 'Cambio aceite', 'Gearboxes ejes 1-3', 'Primer cambio: 12.000h ó 3 años', NULL, 'SOLO el primer cambio a 12.000h. Aceite: Mobil DTE FM 220. Volumen: 0.9L por gearbox (x3 = 2.7L total). Recalibrar ejes 1-3 tras cambio.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 340 (M2004)', '3HAC022546-001', 'Reemplazo', 'Batería SMB (litio 3-cell)', '12-36 meses ó alerta TPU', NULL, 'Solo litio en M2004: 3-cell 3HAB 9999-1. Alerta en TPU cuando batería baja — reemplazar en el mes siguiente a la alerta.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 340 (M2004)', '3HAC022546-001', 'Inspección', 'Ventilador manipulador (rodamientos)', 'c/30.000h ó 5 años', NULL, NULL),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1300', '3HAC070390-001', 'Cambio aceite', 'Reductora eje 1', '1er:6.000h, 2do:24.000h, +c/24.000h', 'OmniCore', 'Aceite y volumen: ver TRM 3HAC042927-001. Solo ejes 1 y 2 tienen cambio de aceite programado.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1300', '3HAC070390-001', 'Cambio aceite', 'Reductora eje 2', '1er:6.000h, 2do:24.000h, +c/24.000h', 'OmniCore', 'Inspección nivel: 64-69mm bajo borde plug, solo tras sospecha fuga / cambio / reparación. Posición robot: A1=0°, A2=-67.5°, A3=0°, A4=0°, A5=0°.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1300', '3HAC070390-001', 'Inspección', 'Etiquetas / Arnés cables / Topes mecánicos (ejes 1-4) / Pintura', 'c/12 meses', 'OmniCore', 'Arnés: reemplazar si daño, grietas o vida útil próxima (40.000h uso normal, 20.000h uso extremo). CleanRoom: inspección pintura diaria + reemplazar topes mecánicos si decoloración o pérdida brillo.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1300', '3HAC070390-001', 'Inspección', 'Correa dentada eje 3 (timing belt)', 'c/12 meses', 'OmniCore', 'Correa eje 4: recomendado inspeccionar al cambiar motor. Reemplazar si desgaste o daño.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1300', '3HAC070390-001', 'Inspección', 'Válvula solenoide (fugas aire)', 'Regularmente', 'OmniCore', 'Verificar ausencia de fugas de aire. Sin intervalo fijo definido en PM.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1300', '3HAC070390-001', 'Lubricación', 'Paquete cables (cable package)', 'Regularmente', 'OmniCore', 'Grasa FM222, art. 3HAC029132-001. Cubrir toda la zona móvil del paquete y las tapas en contacto con él. Reemplazar si daño o desgaste detectado.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1300', '3HAC070390-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001. Incluye circuitos de protección — solo reemplazar con repuesto especificado o equivalente aprobado por ABB.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1300', '3HAC070390-001', 'Verificación', 'Brake Check / Cyclic Brake Check', 'c/8-48h (recomendado)', 'OmniCore', 'Sin SafeMove: rutina Brake Check. Con SafeMove: Cyclic Brake Check. No necesario si ya incluido en aplicación.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1300', '3HAC070390-001', 'Overhaul', 'Robot completo', '30.000h', 'OmniCore', 'Vida gearboxes esperada: 30.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7710', '3HAC089600-001', 'Cambio aceite', 'Reductoras ejes 1-3', 'c/12.000h', 'OmniCore', 'Eje 1: Kyodo Yushi TMO150, ~5.500ml. Eje 2: ~4.300ml. Eje 3: ~4.300ml. NO mezclar con Mobilgear 600 XP 320 usado en ejes 4 sec y 5.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7710', '3HAC089600-001', 'Cambio aceite', 'Reductora eje 4 primaria', 'c/12.000h', 'OmniCore', 'Kyodo Yushi TMO150, ~820ml. WebConfig 3HAC032140-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7710', '3HAC089600-001', 'Cambio aceite', 'Reductora eje 4 secundaria', 'c/12.000h', 'OmniCore', 'Mobilgear 600 XP 320, ~7.250ml. WebConfig 11712016-604. ACEITE DIFERENTE al primario — NO mezclar.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7710', '3HAC089600-001', 'Cambio aceite', 'Reductora eje 5', 'c/12.000h', 'OmniCore', 'Mobilgear 600 XP 320, ~7.500ml. WebConfig 11712016-604. Eje 5 tiene un solo gearbox (sin distinción primario/secundario).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7710', '3HAC089600-001', 'Cambio aceite', 'Reductora eje 6', 'c/12.000h', 'OmniCore', 'Kyodo Yushi TMO150, ~900ml. WebConfig 3HAC032140-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7710', '3HAC089600-001', 'Inspección', 'Disp. equilibrado (dissonancia, daño, fugas, desgaste anillo guía)', 'c/12 meses', 'OmniCore', 'Kits mantenimiento: oreja superior 3HAC091950-001, oreja inferior 3HAC091953-001. Verificar lubricación varilla pistón (capa fina Shell Gadus S2, 3HAC042536-001).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7710', '3HAC089600-001', 'Inspección', 'Sello motor (evacuación en brida)', 'c/12 meses', 'OmniCore', 'Presencia de aceite en sightglass/agujero evacuación → reemplazar motor en momento oportuno.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7710', '3HAC089600-001', 'Inspección', 'Amortiguadores / Etiquetas / Tope mecánico eje 1 / Arnés cables', 'c/12 meses', 'OmniCore', 'Arnés: reemplazar si daño/grietas o vida útil próxima (40.000h normal, 20.000h extremo). Tope eje 1: 3HAC084500-001. Amortiguadores: 3HAC12991-1, 3HAC022338-001, 3HAC085025-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7710', '3HAC089600-001', 'Lubricación', 'Rodamientos esféricos disp. equilibrado + varilla pistón', 'c/20.000h', 'OmniCore', 'Rodamientos: Tribology GR 100-2PD, 85ml/rodamiento (art. 3HAC9408-1). Varilla pistón: Shell Gadus S2 (3HAC042536-001). Lubricar SIEMPRE tras refitting del dispositivo equilibrado. Primera lubricación varilla pistón: tras primeras 150h de operación.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7710', '3HAC089600-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001. Solo reemplazar con repuesto especificado o equivalente aprobado ABB.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7710', '3HAC089600-001', 'Overhaul', 'Robot completo', '40.000h', 'OmniCore', 'Vida esperada gearboxes y disp. equilibrado: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730S', '3HAC092897-001', 'Cambio aceite', 'Reductoras ejes 1-3', 'c/5.000h', 'OmniCore', 'Ejes 1-2: Kyodo Yushi TMO150 4.000ml c/u. Eje 3: TMO150 2.600ml. Intervalo más corto que ejes 4-6 — verificar siempre nivel tras cambio. NO mezclar con Mobilgear XP320 de ejes 4-5.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730S', '3HAC092897-001', 'Cambio aceite', 'Reductoras ejes 4-5', 'c/10.000h', 'OmniCore', 'Eje 4: Mobilgear 600 XP320/XMP320, 7.500ml. Eje 5: variante -270/3.1,-210/3.5,-220/3.1LID,-180/3.5LID = 3.200ml; variante -150/4.0,-130/4.0LID = 2.360ml. WebConfig 11712016-604. ACEITE DIFERENTE a ejes 1-3 — no mezclar.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730S', '3HAC092897-001', 'Cambio aceite', 'Reductora eje 6', 'c/10.000h', 'OmniCore', 'Kyodo Yushi TMO150. Variante -270/3.1,-210/3.5,-220/3.1LID,-180/3.5LID: 600ml. Variante -150/4.0,-130/4.0LID: 370ml. WebConfig 3HAC032140-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730S', '3HAC092897-001', 'Inspección', 'Disp. equilibrado (dissonancia, daño, fugas, holgura)', 'c/12 meses', 'OmniCore', 'Kit mantenimiento oreja enlace: 3HAC087168-001 (sello radial, rodamiento esférico, arandela). Kit mantenimiento cuna: 3HAC088299-001 (sellos, rodamientos ranura, anillos Seeger). Verificar piston rod libre de obstáculos.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730S', '3HAC092897-001', 'Inspección', 'Sello motor (evacuación en brida)', 'c/12 meses', 'OmniCore', 'Aceite en sightglass/evacuación → reemplazar motor en momento oportuno.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730S', '3HAC092897-001', 'Inspección', 'Amortiguadores ejes 2, 3 y 5 / Etiquetas / Tope mecánico eje 1 / Arnés cables', 'c/12 meses', 'OmniCore', 'Amortiguadores: eje2=3HAC046884-001, eje3=3HAC11750-1, eje5=3HAC054956-001. Reemplazar si impresiones >1mm, fisuras o tornillos deformados. Arnés: 40.000h uso normal / 20.000h uso extremo.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730S', '3HAC092897-001', 'Lubricación', 'Rodamiento esférico disp. equilibrado (link ear)', 'c/20.000h', 'OmniCore', 'Grasa Tribology GR100-0PD, 31ml (art. 3HAA1001-294). Lubricar SIEMPRE tras refitting del shaft del dispositivo equilibrado. NOTA: grasa diferente al IRB 7710 (que usa GR100-2PD 85ml).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730S', '3HAC092897-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001. Solo reemplazar con repuesto especificado o equivalente aprobado ABB.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730S', '3HAC092897-001', 'Overhaul', 'Robot completo', '40.000h', 'OmniCore', 'Vida esperada gearboxes y disp. equilibrado: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6760', '3HAC095124-001', 'Cambio aceite', 'Reductoras ejes 1-3', 'c/5.000h', 'OmniCore', 'Eje 1: Kyodo Yushi TMO150 5.900ml. Eje 2: TMO150 4.770ml. Eje 3: TMO150 2.750ml. NO mezclar con Mobilgear XP320 de ejes 4-5. Volúmenes idénticos para ambas variantes.');
