((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6760', '3HAC095124-001', 'Inspección', 'Disp. equilibrado (dissonancia, daño, fugas, holgura)', 'c/12 meses', 'OmniCore', 'Kit cuna/cradle: 3HAC088299-001 (sellos radiales, rodamientos, anillos Seeger). Kit link ear: 3HAC087168-001 (sello radial, rodamiento esférico, O-ring, arandela). Verificar zona pistonrod libre de obstáculos.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6760', '3HAC095124-001', 'Inspección', 'Sello motor (evacuación en brida)', 'c/12 meses', 'OmniCore', 'Aceite en sightglass/evacuación → reemplazar motor en momento oportuno.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6760', '3HAC095124-001', 'Inspección', 'Amortiguadores ejes 2, 3 y 5 / Etiquetas / Tope mecánico eje 1 / Arnés cables', 'c/12 meses', 'OmniCore', 'Amortiguadores: eje2=3HAC046884-001, eje3=3HAC11750-1, eje5=3HAC054956-001 (mismos art. que IRB 6730S). Arnés: 40.000h uso normal / 20.000h uso extremo. PRESS TENDING: si eje opera con ángulo ≤10°, añadir ciclo lubricación c/8h para evitar desgaste prematuro — ejes 1 y 6 especialmente críticos.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6760', '3HAC095124-001', 'Lubricación', 'Rodamiento esférico disp. equilibrado (link ear)', 'c/20.000h', 'OmniCore', 'Grasa Tribology GR100-0PD 31ml (art. 3HAA1001-294). Lubricar SIEMPRE tras refitting del shaft del dispositivo equilibrado. Idéntico a IRB 6730S.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6760', '3HAC095124-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001. Solo reemplazar con repuesto especificado o equivalente aprobado ABB.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6760', '3HAC095124-001', 'Overhaul', 'Robot completo', '40.000h', 'OmniCore', 'Vida esperada gearboxes y disp. equilibrado: 40.000h. En press tending, vida ejes 1 y 6 variable según SPM y carga — verificar con RobotStudio Mechanical Analysis.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730', '3HAC085699-001', 'Cambio aceite', 'Reductoras ejes 1-3', 'c/5.000h', 'OmniCore', 'Eje 1-2: Kyodo Yushi TMO150 3.800ml c/u. Eje 3: TMO150 2.600ml. Volúmenes idénticos para las 5 variantes. NO mezclar con Mobilgear XP320 de ejes 4-5.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730', '3HAC085699-001', 'Cambio aceite', 'Reductoras ejes 4-5', 'c/10.000h', 'OmniCore', 'Eje 4: Mobilgear 600 XP320/XMP320 7.500ml. Eje 5: 3.200ml. WebConfig 11712016-604. ACEITE DIFERENTE a ejes 1-3 — no mezclar.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730', '3HAC085699-001', 'Cambio aceite', 'Reductora eje 6', 'c/10.000h', 'OmniCore', 'Kyodo Yushi TMO150 600ml. WebConfig 3HAC032140-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730', '3HAC085699-001', 'Inspección', 'Disp. equilibrado (dissonancia, daño, fugas, holgura)', 'c/12 meses', 'OmniCore', 'Kit cuna/cradle: 3HAC087164-001 — DIFERENTE al IRB 6730S (que usa 3HAC088299-001). Kit link ear: 3HAC087168-001 (idéntico al 6730S). No intercambiar kits cradle entre IRB 6730 e IRB 6730S.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730', '3HAC085699-001', 'Inspección', 'Sello motor / Amortiguadores ejes 2,3,5 / Etiquetas / Tope eje 1 / Arnés', 'c/12 meses', 'OmniCore', 'Amortiguadores: eje2=3HAC046884-001, eje3=3HAC11750-1, eje5=3HAC054956-001 (idénticos a IRB 6730S y 6760). Arnés: 40.000h normal / 20.000h extremo. Sello motor: aceite en evacuación → reemplazar motor en momento oportuno.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730', '3HAC085699-001', 'Lubricación', 'Rodamiento esférico disp. equilibrado (link ear)', 'c/20.000h', 'OmniCore', 'Grasa Tribology GR100-0PD 31ml (art. 3HAA1001-294). Lubricar SIEMPRE tras refitting del shaft. Idéntico a IRB 6730S y 6760.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730', '3HAC085699-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6730', '3HAC085699-001', 'Overhaul', 'Robot completo', '40.000h', 'OmniCore', 'Vida esperada gearboxes y disp. equilibrado: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6720', '3HAC085697-001', 'Cambio aceite', 'Reductoras ejes 1-3', 'c/5.000h', 'OmniCore', 'Eje 1: Kyodo Yushi TMO150 3.200ml. Eje 2: TMO150 2.600ml. Eje 3: TMO150 2.200ml. Volúmenes idénticos para las 7 variantes. NO mezclar con Mobilgear XP320 de ejes 4-5.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6720', '3HAC085697-001', 'Cambio aceite', 'Reductoras ejes 4-5', 'c/10.000h', 'OmniCore', 'Eje 4: Mobilgear 600 XP320/XMP320 7.600ml (NOTA: 7.600ml, no 7.500ml como IRB 6730). Eje 5: 3.200ml. WebConfig 11712016-604. ACEITE DIFERENTE a ejes 1-3 — no mezclar.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6720', '3HAC085697-001', 'Cambio aceite', 'Reductora eje 6', 'c/10.000h', 'OmniCore', 'Kyodo Yushi TMO150 600ml. WebConfig 3HAC032140-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6720', '3HAC085697-001', 'Inspección', 'Disp. equilibrado (dissonancia, daño, fugas, holgura)', 'c/12 meses', 'OmniCore', 'Kit cuna/cradle: 3HAC087164-001 (idéntico al IRB 6730). Kit link ear: 3HAC087168-001. NO usar kit cradle del IRB 6730S (3HAC088299-001).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6720', '3HAC085697-001', 'Inspección', 'Sello motor / Amortiguadores ejes 2,3,5 / Etiquetas / Tope eje 1 / Arnés', 'c/12 meses', 'OmniCore', 'Amortiguadores: eje2=3HAC046884-001, eje3=3HAC12320-1 (DIFERENTE a IRB 6730/6730S/6760 que usan 3HAC11750-1), eje5=3HAC054956-001. Arnés: 40.000h normal / 20.000h extremo. Sello motor: aceite en evacuación → reemplazar motor en momento oportuno.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6720', '3HAC085697-001', 'Lubricación', 'Rodamiento esférico disp. equilibrado (link ear)', 'c/20.000h', 'OmniCore', 'Grasa Tribology GR100-0PD 50ml (art. 3HAA1001-294). NOTA: 50ml — distinto a IRB 6730/6730S/6760 que usan 31ml. Lubricar SIEMPRE tras refitting del shaft.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6720', '3HAC085697-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001. Solo reemplazar con repuesto especificado o equivalente aprobado ABB.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6720', '3HAC085697-001', 'Overhaul', 'Robot completo', '40.000h', 'OmniCore', 'Vida esperada gearboxes y disp. equilibrado: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6750S', '3HAC092901-001', 'Cambio aceite', 'Reductoras ejes 1-3', 'c/5.000h', 'OmniCore', 'Ejes 1-2: Kyodo Yushi TMO150 5.600ml c/u (idéntico para todas las variantes). Eje 3: TMO150 3.300ml (idéntico para todas las variantes). NO mezclar con Mobilgear XP320 de ejes 4-5.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6750S', '3HAC092901-001', 'Cambio aceite', 'Reductoras ejes 4-5', 'c/10.000h', 'OmniCore', 'Eje 4: Mobilgear 600 XP320/XMP320 8.000ml (idéntico todas variantes). Eje 5: -350/3.2 y -270/3.2LID = 4.600ml; -270/3.6,-215/3.9,-220/3.6LID,-185/3.9LID = 3.200ml. WebConfig 11712016-604. ACEITE DIFERENTE a ejes 1-3 — no mezclar.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6750S', '3HAC092901-001', 'Cambio aceite', 'Reductora eje 6', 'c/10.000h', 'OmniCore', 'Kyodo Yushi TMO150. -350/3.2 y -270/3.2LID: 400ml. -270/3.6,-215/3.9,-220/3.6LID,-185/3.9LID: 600ml. WebConfig 3HAC032140-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6750S', '3HAC092901-001', 'Inspección', 'Disp. equilibrado (dissonancia, daño, fugas, holgura)', 'c/12 meses', 'OmniCore', 'Kit cuna/cradle: 3HAC088299-001 (=IRB 6730S/6760; NO el 3HAC087164-001 de IRB 6730/6720). Kit link ear: 3HAC087168-001 (idéntico a todos). Incluye comprobación holgura bajo disp. equilibrado (punto D).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6750S', '3HAC092901-001', 'Inspección', 'Sello motor / Amortiguadores ejes 2,3,5 / Etiquetas / Tope eje 1 / Arnés', 'c/12 meses', 'OmniCore', 'Amortiguadores: eje2=3HAC046884-001, eje3=3HAC11750-1, eje5=3HAC054956-001 (idénticos a IRB 6730/6730S/6760; el IRB 6720 usa 3HAC12320-1 en eje 3). Arnés: 40.000h normal / 20.000h extremo.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6750S', '3HAC092901-001', 'Lubricación', 'Rodamiento esférico disp. equilibrado (link ear)', 'c/20.000h', 'OmniCore', 'Grasa Tribology GR100-0PD 31ml (art. 3HAA1001-294). Lubricar SIEMPRE tras refitting del shaft. Idéntico a IRB 6730/6730S/6760 (no 50ml del IRB 6720).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6750S', '3HAC092901-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001. Solo reemplazar con repuesto especificado o equivalente aprobado ABB.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6750S', '3HAC092901-001', 'Overhaul', 'Robot completo', '40.000h', 'OmniCore', 'Vida esperada gearboxes y disp. equilibrado: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6740', '3HAC085701-001', 'Cambio aceite', 'Reductoras ejes 1-3', 'c/5.000h', 'OmniCore', 'Eje 1: Kyodo Yushi TMO150 3.800ml. Eje 2: TMO150 4.300ml (mayor que eje 1 — verificar procedimiento). Eje 3: TMO150 2.600ml. Idéntico para las 6 variantes. NO mezclar con Mobilgear XP320 de ejes 4-5.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6740', '3HAC085701-001', 'Cambio aceite', 'Reductoras ejes 4-5', 'c/10.000h', 'OmniCore', 'Eje 4: Mobilgear 600 XP320/XMP320 8.400ml (idéntico todas variantes). Eje 5: -310/2.8,-260/3.0,-270/2.8LID,-230/3.0LID = 4.600ml; -240/3.2,-220/3.2LID = 3.200ml. WebConfig 11712016-604. ACEITE DIFERENTE a ejes 1-3 — no mezclar.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6740', '3HAC085701-001', 'Cambio aceite', 'Reductora eje 6', 'c/10.000h', 'OmniCore', 'Kyodo Yushi TMO150. -310/2.8,-260/3.0,-270/2.8LID,-230/3.0LID: 400ml. -240/3.2,-220/3.2LID: 600ml. WebConfig 3HAC032140-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6740', '3HAC085701-001', 'Inspección', 'Disp. equilibrado / Amortiguadores ejes 2,3,5 / Etiquetas / Tope eje 1 / Sello motor / Arnés', 'c/12 meses', 'OmniCore', 'Cradle: 3HAC088299-001. Link ear: 3HAC087168-001. Amortiguadores: eje2=3HAC046884-001, eje3=3HAC11750-1, eje5=3HAC054956-001. Arnés: 40.000h normal / 20.000h extremo.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6740', '3HAC085701-001', 'Lubricación', 'Rodamiento esférico disp. equilibrado (link ear)', 'c/20.000h', 'OmniCore', 'Grasa Tribology GR100-0PD 31ml (art. 3HAA1001-294). Lubricar SIEMPRE tras refitting del shaft.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6740', '3HAC085701-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6740', '3HAC085701-001', 'Overhaul', 'Robot completo', '40.000h', 'OmniCore', 'Vida esperada gearboxes y disp. equilibrado: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 930', '3HAC086009-001', 'Cambio aceite', 'Reductora eje 1 — 1ª vez', 'c/6.000h DTC', 'OmniCore', 'Kyodo Yushi TMO150 590ml (art. 3HAC032140-009 — distinto al -001 de la familia 67xx). Cambios siguientes cada 20.000h. SCARA: solo ejes 1-2 tienen gearbox con aceite; ejes 3-4 usan ball screw con grasa.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 930', '3HAC086009-001', 'Cambio aceite', 'Reductora eje 2 — 1ª vez', 'c/6.000h DTC', 'OmniCore', 'Kyodo Yushi TMO150 215ml (art. 3HAC032140-009). Cambios siguientes cada 20.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 930', '3HAC086009-001', 'Cambio aceite', 'Reductoras ejes 1 y 2 — cambios siguientes', 'c/20.000h DTC', 'OmniCore', 'Eje 1: TMO150 590ml. Eje 2: TMO150 215ml. Art. 3HAC032140-009. Primera vez a 6.000h; siguientes cada 20.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 930', '3HAC086009-001', 'Inspección / Lubricación', 'Ball screw spline unit (ejes 3-4) / Timing belts / Stops mecánicos / Etiquetas / Arnés', 'c/12 meses', 'OmniCore', 'Ball screw: inspeccionar desgaste, abrasión y cantidad de grasa en shaft. Lubricar con THK AFA Grease 2g si hay degradación (decoloración, sequedad) o insuficiencia. Timing belt eje 3: tensión 36.6-41.8N/139-149Hz (usado). Timing belt eje 4: tensión 36.3-41.4N/312-333Hz (usado). Medir con tensiómetro sónico. Stops mecánicos: ejes 1, 2 y 3 — reemplazar si doblados, sueltos o dañados. Arnés: sin distinción normal/extremo — vida 20.000h en ambos casos.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 930', '3HAC086009-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Ver procedimiento "Replacing the SMB unit and battery unit" pág. 134 del PM. Número de artículo no especificado en el schedule — consultar PM.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 930', '3HAC086009-001', 'Mantenimiento recomendado', 'Brake Check / Cyclic Brake Check', 'c/8-48h (recomendado)', 'OmniCore', 'Sin opción SafeMove: ejecutar Brake Check routine. Con opción SafeMove: ejecutar Cyclic Brake Check. No necesario si ya está incluido en la aplicación.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 930', '3HAC086009-001', 'Overhaul', 'Robot completo', 'c/20.000h', 'OmniCore', 'Vida esperada gearboxes: 20.000h (MENOR que familia 67xx con 40.000h). Arnés: 20.000h normal y extremo.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5350', '3HNA019729-001', 'Cambio aceite', 'Reductoras ejes 1, 2, 3 y trolley — 1ª vez', 'c/6.000h DTC (1ª vez)', 'IRC5P', 'Eje 1: Kyodo Yushi TMO150 1.400ml. Eje 2: TMO150 1.000ml. Eje 3: Mobil Mobilgear 600 XP320 650ml. Eje trolley: Mobilgear XP320 1.500ml. ATENCIÓN: TMO150 (ejes 1-2) y XP320 (ejes 3-trolley) son incompatibles — NO mezclar. Primera vez a 6.000h, siguientes cada 24.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5350', '3HNA019729-001', 'Cambio aceite', 'Reductoras ejes 1, 2, 3 y trolley — cambios siguientes', 'c/24.000h DTC', 'IRC5P', 'Mismos volúmenes y aceites que primer cambio. Eje 1: TMO150 1.400ml. Eje 2: TMO150 1.000ml. Eje 3: XP320 650ml. Trolley: XP320 1.500ml.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5350', '3HNA019729-001', 'Lubricación', 'Rodamientos eje 3 (grease nipple superior e inferior)', 'c/2.000h', 'IRC5P', 'Shell Gadus S2 V220 2 grease. Bombear grasa y mover eje 3 entre aplicaciones. Acceso requiriendo mover tower a posición inferior.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5350', '3HNA019729-001', 'Lubricación / Inspección', 'Raíles, cremallera y runner blocks (solo versión trolley 4 ejes)', 'c/500h', 'IRC5P', 'Kyodo Yushi Unilite No. 2. Limpiar raíles antes de lubricar. Runner blocks: lubricar tras ~100 km recorridos. Limpiar runner blocks regularmente y proteger de contaminación. Solo aplica a versión 4 ejes montada sobre raíl.');
INSERT INTO `actividades_mantenimiento` (fabricante_id, familia_robot, documento, tipo_actividad, componente, intervalo_estandar, intervalo_foundry, notas) VALUES
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5350', '3HNA019729-001', 'Inspección', 'Test frenos de ejes', 'c/500h', 'IRC5P', 'Mover cada eje a posición de carga máxima. Desconectar motores. Verificar que todos los ejes mantienen posición.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5350', '3HNA019729-001', 'Inspección', 'Nivel aceite en reductoras', 'c/5 años', 'IRC5P', 'Verificar nivel según especificaciones: eje1=25±3mm bajo superficie tapón, eje2=40±3mm, eje3=50±3mm. Trolley: verificar con tapón nivel lateral. Rellenar con aceite especificado si bajo.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5350', '3HNA019729-001', 'Inspección diaria', 'Limpieza, fugas aceite, holgura engranajes, cables, juntas cubiertas', 'Regularmente', 'IRC5P', 'Limpiar con paño húmedo sin disolventes fuertes. Evitar limpieza a presión directa. Inspeccionar fugas aceite, holgura en engranajes, estado cables y juntas. ATEX: usar paño húmedo para evitar electricidad estática en superficies no conductoras.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5350', '3HNA019729-001', 'Overhaul', 'Sin intervalo de overhaul definido en PM', NULL, 'IRC5P', 'PM no define intervalo de overhaul completo. Seguir programa de mantenimiento preventivo y consultar ABB para aplicaciones especiales.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5710', '3HAC075184-001', 'Cambio aceite', 'Reductoras ejes 1-3', 'c/5.000h', 'OmniCore', 'Eje 1: TMO150 3.900ml (suelo) / 4.350ml (invertido) — idéntico para todas las variantes. Eje 2: TMO150 2.500ml (idéntico todos). Eje 3: -110/2.3 y -90/2.3LID = 1.600ml; -90/2.7 y -70/2.7LID = 1.700ml. WebConfig 3HAC032140-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5710', '3HAC075184-001', 'Cambio aceite', 'Reductoras ejes 4-6', 'c/10.000h', 'OmniCore', 'Eje 4: XP320 5.000ml (idéntico todos). Eje 5: -110/2.3 y -90/2.3LID = 1.890ml; -90/2.7 y -70/2.7LID = 1.170ml. Eje 6: -110/2.3 y -90/2.3LID = TMO150 370ml; -90/2.7 y -70/2.7LID = TMO150 220ml. E4-E5: WebConfig 11712016-604. E6: 3HAC032140-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5710', '3HAC075184-001', 'Inspección', 'Amortiguadores ejes 2,3,5 / Etiquetas / Tope eje 1 / Sello motor / Arnés', 'c/12 meses', 'OmniCore', 'Amortiguadores: eje2=3HAC12320-1, eje3=3HAC12320-1, eje5=3HAC054956-001. NOTA: ejes 2 y 3 usan el MISMO artículo 3HAC12320-1 (distinto a IRB 6730/6740/6750S/6760 donde eje2=3HAC046884-001). Sin dispositivo de equilibrado (diferencia clave vs familia IRB 67xx con equilibrado).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5710', '3HAC075184-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001. Overhaul gearboxes: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5720', '3HAC079195-001', 'Cambio aceite', 'Reductoras ejes 1-3', 'c/5.000h', 'OmniCore', 'Eje 1: TMO150 3.900ml (suelo) / 4.350ml (invertido) — idéntico para todas las variantes. Eje 2: TMO150 3.800ml (idéntico todos — mayor que IRB 5710 eje2=2.500ml). Eje 3: TMO150 1.700ml (idéntico todos). WebConfig 3HAC032140-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5720', '3HAC079195-001', 'Cambio aceite', 'Reductoras ejes 4-6', 'c/10.000h', 'OmniCore', 'Eje 4: XP320 5.000ml (idéntico todos). Eje 5: -125/3.0 y -90/3.0LID = 1.890ml; -180/2.6 y -155/2.6LID = 2.360ml. Eje 6: -125/3.0 y -90/3.0LID = TMO150 370ml; -180/2.6 y -155/2.6LID = TMO150 380ml. E4-E5: WebConfig 11712016-604. E6: 3HAC032140-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5720', '3HAC079195-001', 'Inspección', 'Amortiguadores ejes 2,3,5 / Etiquetas / Tope eje 1 / Sello motor / Arnés', 'c/12 meses', 'OmniCore', 'Amortiguadores: eje2=3HAC12320-1, eje3=3HAC12320-1, eje5=3HAC054956-001. Idénticos a IRB 5710. Sin dispositivo de equilibrado.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5720', '3HAC079195-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001. Overhaul gearboxes: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7720', '3HAC089605-001', 'Cambio aceite', 'Todos los ejes (1-6 + eje4 secundario)', 'c/12.000h', 'OmniCore', 'Intervalo ÚNICO c/12.000h para todos los ejes (no hay c/5.000h ni c/10.000h como resto familia OmniCore). Eje 1: TMO150 5.500ml. Eje 2: TMO150 4.300ml. Eje 3: TMO150 4.300ml. Eje 4 primario: TMO150 1.680ml. Eje 4 secundario: XP320 9.400ml (idéntico todos). Eje 5: -620/2.9,-530/3.1,-560/2.9LID,-480/3.1LID = XP320 10.000ml; -510/3.3,-450/3.5,-400/3.3LID = XP320 7.500ml. Eje 6: grupo A = TMO150 1.300ml; grupo B = TMO150 900ml. EJE 4 TIENE DOS GEARBOXES SEPARADOS con aceites incompatibles — NO confundir.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7720', '3HAC089605-001', 'Inspección', 'Disp. equilibrado / Amortiguadores / Etiquetas / Tope eje 1 / Sello motor / Arnés', 'c/12 meses', 'OmniCore', 'Disp. equilibrado: kit upper ear 3HAC091950-001, kit lower ear 3HAC091953-001 (DIFERENTES a familia IRB 67xx — no intercambiables). Amortiguadores: A(ejes2-3)=3HAC12991-1, B(lower arm)=3HAC022338-001, C(eje5/muñeca)=3HAC085025-001 — completamente diferentes a IRB 5710/5720/67xx. Disp. equilibrado incluye inspección guide ring, piston rod y holgura.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7720', '3HAC089605-001', 'Lubricación', 'Rodamientos disp. equilibrado (2 pcs) + varilla pistón', 'c/20.000h', 'OmniCore', 'Rodamientos (2 uds): Triboly GR100-2PD 85ml/rodamiento (art. 3HAC9408-1). DIFERENTE a familia IRB 67xx (GR100-0PD 31/50ml). Varilla pistón: Shell Gadus S2 (art. 3HAC042536-001) — capa fina sobre superficie no pintada. Lubricar SIEMPRE tras refitting del dispositivo de equilibrado. Pre-lubricado de fábrica; limpiar grasa de transporte tras primer test run.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7720', '3HAC089605-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001. Overhaul gearboxes y disp. equilibrado: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5710', '3HAC075184-001', 'Cambio aceite', 'Reductoras ejes 1-3', 'c/5.000h', 'OmniCore', 'Eje 1: TMO150 3.900ml (floor) / 4.350ml (Inverted) — idéntico para las 4 variantes. Eje 2: TMO150 2.500ml (idéntico todas variantes). Eje 3: -110/2.3 y -90/2.3LID = 1.600ml; -90/2.7 y -70/2.7LID = 1.700ml.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5710', '3HAC075184-001', 'Cambio aceite', 'Reductoras ejes 4-6', 'c/10.000h', 'OmniCore', 'Eje 4: Mobilgear XP320 5.000ml (idéntico todas variantes). Eje 5: -110/2.3 y -90/2.3LID = 1.890ml; -90/2.7 y -70/2.7LID = 1.170ml. Eje 6: -110/2.3 y -90/2.3LID = 370ml; -90/2.7 y -70/2.7LID = 220ml. WebConfig eje4-5: 11712016-604. SIN dispositivo equilibrado (no hay cambio c/20.000h).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5710', '3HAC075184-001', 'Inspección', 'Amortiguadores ejes 2,3,5 / Etiquetas / Tope eje 1 / Sello motor / Arnés', 'c/12 meses', 'OmniCore', 'Amortiguadores: eje2=3HAC12320-1, eje3=3HAC12320-1 (ejes 2 y 3 usan MISMO artículo), eje5=3HAC054956-001. DIFERENTE a familia 67xx: el IRB 5710 NO tiene amortiguador 3HAC046884-001 ni 3HAC11750-1. Arnés: 40.000h normal / 20.000h extremo. Overhaul gearboxes: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5720', '3HAC079195-001', 'Cambio aceite', 'Reductoras ejes 1-3', 'c/5.000h', 'OmniCore', 'Eje 1: TMO150 3.900ml (floor) / 4.350ml (Inverted) — idéntico para las 4 variantes. Eje 2: TMO150 3.800ml (idéntico todas variantes — mayor que IRB 5710 con 2.500ml). Eje 3: TMO150 1.700ml (idéntico todas variantes).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5720', '3HAC079195-001', 'Cambio aceite', 'Reductoras ejes 4-6', 'c/10.000h', 'OmniCore', 'Eje 4: Mobilgear XP320 5.000ml (idéntico todas variantes). Eje 5: -125/3.0 y -90/3.0LID = 1.890ml; -180/2.6 y -155/2.6LID = 2.360ml. Eje 6: -125/3.0 y -90/3.0LID = 370ml; -180/2.6 y -155/2.6LID = 380ml. SIN dispositivo equilibrado.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 5720', '3HAC079195-001', 'Inspección', 'Amortiguadores ejes 2,3,5 / Etiquetas / Tope eje 1 / Sello motor / Arnés', 'c/12 meses', 'OmniCore', 'Amortiguadores: eje2=3HAC12320-1, eje3=3HAC12320-1, eje5=3HAC054956-001. Idénticos a IRB 5710. Arnés: 40.000h normal / 20.000h extremo.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7720', '3HAC089605-001', 'Cambio aceite', 'Reductoras ejes 1-3', 'c/12.000h', 'OmniCore', 'Intervalo DIFERENTE a familia 57xx/67xx (c/12.000h no c/5.000h). Eje 1: TMO150 5.500ml. Eje 2: TMO150 4.300ml. Eje 3: TMO150 4.300ml. Idéntico para las 8 variantes. WebConfig 3HAC032140-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7720', '3HAC089605-001', 'Cambio aceite', 'Reductora eje 4 — DOS gearboxes', 'c/12.000h', 'OmniCore', 'EJE 4 TIENE DOS REDUCTORAS CON ACEITES DIFERENTES — no confundir. Gearbox primario: Kyodo Yushi TMO150 1.680ml (art. 3HAC032140-001). Gearbox secundario: Mobilgear 600 XP320 9.400ml (art. 11712016-604). Idéntico para las 8 variantes.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7720', '3HAC089605-001', 'Cambio aceite', 'Reductoras ejes 5-6', 'c/20.000h', 'OmniCore', 'Intervalo DIFERENTE a ejes 1-4 (c/20.000h). Eje 5: -620/2.9,-530/3.1,-560/2.9LID,-480/3.1LID = 10.000ml XP320; -510/3.3,-450/3.5,-400/3.3LID = 7.500ml XP320. Eje 6: -620/2.9,-530/3.1,-560/2.9LID,-480/3.1LID = 1.300ml TMO150; -510/3.3,-450/3.5,-400/3.3LID = 900ml TMO150.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7720', '3HAC089605-001', 'Inspección', 'Disp. equilibrado / Amortiguadores / Etiquetas / Tope eje 1 / Sello motor / Arnés', 'c/12 meses', 'OmniCore', 'Equilibrado tipo PISTÓN (no muelle/spring como familia 67xx): inspeccionar guía-ring, lubricación pistón, holgura, dissonancia y fugas. Kits: upper ear=3HAC091950-001, lower ear=3HAC091953-001. Amortiguadores totalmente distintos: A(eje2/3)=3HAC12991-1, B(lower arm)=3HAC022338-001, C(wrist)=3HAC085025-001. Arnés: 40.000h normal / 20.000h extremo.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7720', '3HAC089605-001', 'Lubricación', 'Rodamientos disp. equilibrado (upper+lower ear) y pistón', 'c/20.000h', 'OmniCore', 'Rodamientos: Tribology GR100-2PD 85ml/rodamiento (art. 3HAC9408-1). NOTA: GR100-2PD — diferente al GR100-0PD de familia 67xx. 85ml (no 31ml ni 50ml). Hay 2 rodamientos (upper + lower ear). Pistón: Shell Gadus S2 art. 3HAC042536-001 — capa fina en superficie no pintada. Lubricar pistón también tras 1ª instalación y tras inspección si necesario.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7720', '3HAC089605-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001. Incluye circuitos de protección.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 7720', '3HAC089605-001', 'Overhaul', 'Robot completo', '40.000h', 'OmniCore', 'Vida esperada gearboxes y disp. equilibrado: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1520ID', '3HAC043435-001', 'Cambio aceite', 'Reductoras ejes 1, 2, 3', '1ª cambio c/6.000h DTC; 2ª c/24.000h; siguientes c/24.000h', 'IRC5 / OmniCore', 'Eje 1: TMO150 350ml (suelo) / 600ml (suspendida). Eje 2: TMO150 520ml. Eje 3: TMO150 320ml. WebConfig 3HAC032140-001. Ejes 4 y 5 individuales: NO requieren cambio de aceite. Eje 4: XP320 350ml (WebConfig 11712016-604) — solo inspección de nivel.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1520ID', '3HAC043435-001', 'Cambio aceite/grasa', 'Muñeca ID ejes 5-6 (gearbox integrado)', '1ª cambio c/6.000h DTC; 2ª c/24.000h; siguientes c/24.000h', 'IRC5 / OmniCore', 'Eje 5-6 (ID): Optimol Optigear BM100 (art. 3HAC0860-1). Cantidad gearbox nuevo: 130ml. Recarga tras drenado: 110ml (MENOR — no rellenar al nivel de nuevo). ADVERTENCIA: cantidad de recarga ≠ cantidad gearbox nuevo.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1520ID', '3HAC043435-001', 'Inspección', 'Nivel aceite ejes 1-3 c/12m; ejes 4-5 c/48m; eje 5-6(ID) c/12m; Amortiguadores ejes 2,3 / Etiquetas / Arnés / Tope mecánico', 'c/12 meses (ejes 1-3, ID); c/48 meses (ejes 4-5)', 'IRC5 / OmniCore', 'Ejes 4 y 5 inspeccionan nivel c/48 meses (intervalo más largo que resto). Eje 6 individual: NO requiere inspección. Amortiguadores en ejes 2 y 3 — artículo en catálogo externo ABB Robotics One (no en PM Rev.T). Batería: RMU101=3HAC044168-001 / RMU102=3HAC043904-001 (c/36m); DSQC633A 2-pin (alerta baja). Overhaul: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 120', '3HAC035728-001', 'Inspección', 'Amortiguadores ejes 1,2,3 / Arnés / Correas dentadas ejes 3,5 / Cubiertas plástico / Topes mecánicos / Etiquetas', 'Regularmente (amort., arnés, cubiertas, topes) / c/36 meses (correas)', 'IRC5', 'SIN cambio de aceite en ningún eje — todos los ejes usan GRASA (no aceite). ÚNICO robot en esta categoría. Overhaul: 30.000h (menor que resto de familia = 40.000h). Amortiguadores en ejes 1, 2 y 3 — artículos en catálogo externo. Correas dentadas eje3: F=18-19.7N (nuevo)/12.5-14.3N (usado). Correas dentadas eje5: F=7.6-8.4N (nuevo)/5.3-6.1N (usado). Batería: 3-pin RMU101 c/36m ó alerta baja; 2-pin DSQC633A alerta baja.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6710', '3HAC085695-001', 'Cambio aceite', 'Reductoras ejes 1-3', 'c/5.000h DTC', 'OmniCore', 'Eje 1: TMO150 3.200ml. Eje 2: TMO150 2.600ml. Eje 3: TMO150 2.200ml. WebConfig 3HAC032140-001. Idéntico para las 4 variantes.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6710', '3HAC085695-001', 'Cambio aceite', 'Reductoras ejes 4-6', 'c/10.000h DTC', 'OmniCore', 'Eje 4: XP320/XMP320 7.600ml. Eje 5: XP320/XMP320 2.360ml. Eje 6: TMO150 380ml. E4-E5: WebConfig 11712016-604. E6: 3HAC032140-001. Idéntico para las 4 variantes.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6710', '3HAC085695-001', 'Inspección', 'Disp. equilibrado / Amortiguadores ejes 2,3,5 / Sello motor / Arnés / Etiquetas / Tope eje1', 'c/12 meses', 'OmniCore', 'Amortiguadores: eje2=3HAC046884-001, eje3=3HAC12320-1, eje5=3HAC054956-001. NOTA: eje2 (3HAC046884-001) es DIFERENTE a IRB 5710/5720 donde eje2=3HAC12320-1 igual que eje3. Kits equilibrado: cradle=3HAC087164-001 (2 rodamientos), link ear=3HAC087168-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6710', '3HAC085695-001', 'Lubricación', 'Rodamiento esférico disp. equilibrado', 'c/20.000h DTC', 'OmniCore', 'Grasa: Triboly GR100-0PD 50ml (art. 3HAA1001-294). UN rodamiento. Lubricar siempre tras refitting del eje del disp. equilibrado. Batería SMB: 3HAC044075-001 c/36m ó alerta baja. Overhaul: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6700Inv', '3HAC058254-001', 'Cambio aceite', 'Todos los ejes (1-6)', 'c/12.000h DTC', 'IRC5 / OmniCore', 'Intervalo ÚNICO c/12.000h para todos los ejes — NO c/5.000h/c/10.000h como IRB 6700 estándar. Variantes -300/2.60,-245/2.90: E1=~4.900ml, E2=~4.000ml, E3=~3.500ml, E4(XP320)=~12.500ml, E5(XP320)=~4.500ml, E6=~700ml. TMO150: 3HAC032140-001. XP320/XMP320: 11712016-604. ADVERTENCIA: Volúmenes en TRM son aproximados (~) para esta familia.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6700Inv', '3HAC058254-001', 'Inspección', 'Velcro straps arnés c/6m / Sello motor+disp.equilibrado+arnés+etiquetas+lock transporte c/12m / Amortiguadores ejes 2,3 + tope mecánico c/24m', 'c/6m, c/12m, c/24m (según actividad)', 'IRC5 / OmniCore', 'Robot invertido: intervalos distintos a robots de suelo. Dampers inspeccionan c/24m (vs c/12m resto familia 67xx). Amortiguadores ejes 2 y 3 (2 pcs cada uno) — artículos en catálogo externo. Batería: c/36m ó alerta baja (art. en catálogo externo). Incluye inspección de tornillo de bloqueo de transporte.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6700Inv', '3HAC058254-001', 'Lubricación', 'Rodamiento esférico disp. equilibrado', 'c/20.000h DTC', 'IRC5 / OmniCore', 'Grasa: Shell Gadus S2 (art. 3HAC042536-001). DIFERENTE a IRB 6710 que usa GR100-0PD. Lubricar siempre tras refitting del eje del disp. equilibrado. Overhaul: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 8700', '3HAC052853-001', 'Cambio aceite', 'Todos los ejes (1-6 + eje4 secundario)', 'c/12.000h DTC', 'IRC5 / OmniCore', 'Intervalo c/12.000h para todos los ejes (no c/5k/c/10k). Eje 1: TMO150 5.600ml. Eje 2: TMO150 5.400ml. Eje 3: TMO150 5.400ml. Eje 4 primario: TMO150 1.650ml. Eje 4 secundario: XP320 9.400ml. Eje 5: XP320 16.500ml (MAYOR volumen de toda la BD). Eje 6: TMO150 1.550ml. EJE 4 TIENE DOS GEARBOXES con aceites incompatibles — no confundir. TMO150: 3HAC032140-001. XP320/XMP320: 11712016-604.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 8700', '3HAC052853-001', 'Inspección', 'Nivel aceite todos los ejes (incl. eje 4 prim./sec.) / Plugs transparentes / Disp. equilibrado / Arnés / Etiquetas / Amortiguadores / Tope mecánico', 'c/12 meses', 'IRC5 / OmniCore', 'Amortiguadores: brazo inferior y paralelo=3HAC12991-1 (7 uds), muñeca=3HAC050601-001 (2 uds). Mismos artículos de lower arm que IRB 7720. Inspección de plugs transparentes única en esta familia.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 8700', '3HAC052853-001', 'Lubricación', 'Rodamientos esféricos disp. equilibrado (x2) + rodamiento rodillos cruzados eje1 + rodamiento esférico brazo inferior', 'c/20.000h DTC', 'IRC5 / OmniCore', '1. Rodamientos disp. equilibrado: GR100-2PD 25ml/rodamiento (art. 3HAC073286-001). DIFERENTE a IRB 6710 (GR100-0PD 50ml). 2. Rodamiento rodillos cruzados (cross roller bearing eje1): Mobillux EP2, 3g x 2 nipples (sin art. específico en PM). Lubricar rotando eje1 hasta tope mecánico en ambas direcciones. 3. Rodamiento esférico brazo inferior: Mobillux EP2, 3-6g (sin art. específico en PM). NOTA: Cross roller bearing c/6m en entornos agresivos (forja, fundición). Batería: artículo en catálogo externo. Overhaul: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1010', '3HAC081964-001', 'Inspección', 'Arnés / Correas dentadas ejes 3,5 / Topes mecánicos / Etiquetas / Robot general', 'Regularmente (general), c/12 meses (etiquetas, arnés, correas, topes)', 'OmniCore', 'Mini-robot industria 3C (payload 1.5 kg). SIN cambio de aceite — no aparece en TRM. SIN amortiguadores en schedule de mantenimiento. Correas dentadas eje 3: F nuevo=20.2±1N / usado=14.1±1N; frecuencia nuevo=93-118Hz / usado=86-93Hz. Correas dentadas eje 5: F nuevo=19.6±1N / usado=13.7±1N; frecuencia nuevo=132-169Hz / usado=123-131Hz.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1010', '3HAC081964-001', 'Lubricación', 'Arnés/cable package', 'c/12 meses (si hay daño/desgaste)', 'OmniCore', 'Grasa FM222 (art. 3HAC029132-001). Aplicar sobre toda la zona móvil del cable y las cubiertas en contacto. Reemplazar cable package completo si se detecta daño.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1010', '3HAC081964-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001 (idéntico a familia). Overhaul: 20.000h DTC. Cable harness life: 20.000h (normal y extremo).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1090', '3HAC088056-001', 'Inspección', 'Arnés (upper+lower) / Correas dentadas TODOS los ejes / Etiquetas / Robot general', 'Regularmente / c/12 meses / c/36 meses', 'OmniCore', 'ROBOT EDUCATIVO (solo para training) — requiere etiqueta identificativa en uso. SIN cambio de aceite en reductoras — no aparece en TRM. Correas dentadas en TODOS los ejes (1-6) — inspección visual únicamente (sin tensiones en PM Rev.E). NOTA: correas ejes 1 y 4 solo accesibles tras retirar motores (recomendado inspeccionar al cambiar motor). Cable package dividido en 2 segmentos: upper y lower (división dentro del swing).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1090', '3HAC088056-001', 'Lubricación', 'Arnés/cable package (upper+lower)', 'c/12 meses', 'OmniCore', 'Grasa FM222 (art. 3HAC029132-001). Aplicar sobre cable package completo y cubiertas en contacto.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1090', '3HAC088056-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001. OVERHAUL: 10.000h DTC (ÚNICO robot con overhaul tan bajo). Life expectancy: gearboxes 10.000h + cable harness 10.000h (uso normal Y extremo) — muy limitado.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1100', '3HAC064992-001', 'Inspección', 'Arnés (upper+lower) / Correas dentadas ejes 1-6 / Pintura / Etiquetas / Robot general', 'Regularmente (general, diario en CleanRoom) / c/12 meses', 'OmniCore', 'SIN cambio de aceite en reductoras — no aparece en TRM. SIN amortiguadores en schedule. Protección: Standard IP40, IP67 (opción), CleanRoom. CleanRoom requiere INSPECCIÓN DIARIA (no regularmente). Aplicaciones L/H/P (Life science/Healthcare/Pharma) pueden reducir vida útil significativamente. Correas dentadas en los 6 ejes — ejes 1 y 4 solo accesibles tras retirar motor. Cable package en 2 segmentos (upper + lower). Inspección de pintura añadida (relevante para aplicaciones CleanRoom).');
INSERT INTO `actividades_mantenimiento` (fabricante_id, familia_robot, documento, tipo_actividad, componente, intervalo_estandar, intervalo_foundry, notas) VALUES
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1100', '3HAC064992-001', 'Lubricación', 'Arnés/cable package (upper+lower)', 'c/12 meses', 'OmniCore', 'Grasa FM222 (art. 3HAC029132-001). Aplicar sobre cable package y cubiertas.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1100', '3HAC064992-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001. Overhaul: 30.000h DTC. Life expectancy: gearboxes 30.000h + cable harness 30.000h (normal y extremo). CBC (Cyclic Brake Check) disponible con opción SafeMove — sustituye al Brake Check estándar.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1510ID', '3HAC087870-001', 'Cambio aceite', 'Reductoras ejes 1, 2, 3', '1ª cambio c/6.000h DTC; 2ª c/24.000h; siguientes c/24.000h', 'IRC5 / IRC5C / OmniCore', 'Volúmenes IDÉNTICOS al IRB 1520ID. Eje 1: TMO150 350ml (suelo) / 600ml (suspendida). Eje 2: TMO150 520ml. Eje 3: TMO150 320ml. WebConfig 3HAC032140-001. Ejes 4 y 5 individuales: NO cambio de aceite. Eje 4 XP320 350ml (WebConfig 11712016-604) — solo inspección.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1510ID', '3HAC087870-001', 'Cambio aceite/grasa', 'Muñeca ID ejes 5-6 (gearbox integrado)', '1ª cambio c/6.000h DTC; 2ª c/24.000h; siguientes c/24.000h', 'IRC5 / IRC5C / OmniCore', 'Eje 5-6 (ID): Optimol Optigear BM100 (art. 3HAC0860-1). Cantidad gearbox nuevo: 130ml. Recarga tras drenado: 110ml. ADVERTENCIA: cantidad de recarga ≠ cantidad gearbox nuevo.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 1510ID', '3HAC087870-001', 'Inspección', 'Nivel aceite ejes 1-3 c/12m; ejes 4-5 c/48m; eje 5-6(ID) c/12m; Amortiguadores ejes 2,3 / Etiquetas / Arnés / Tope mecánico', 'c/12 meses (ejes 1-3, ID); c/48 meses (ejes 4-5)', 'IRC5 / IRC5C / OmniCore', 'Schedule IDÉNTICO al IRB 1520ID — clon mecánico. Ejes 4 y 5 inspeccionan nivel c/48 meses. Eje 6 individual: NO requiere inspección. Nivel aceite eje 1: suelo=39±3mm por debajo brida motor; suspendida=22±3mm. Amortiguadores en ejes 2 y 3 — artículo en catálogo externo ABB Robotics One (no en PM Rev.E). Batería: RMU101=3HAC044168-001 / RMU102=3HAC043904-001 (c/36m); DSQC633A 2-pin (alerta baja). Overhaul: 40.000h. Controladores soportados: IRC5 + IRC5C + OmniCore (más amplio que IRB 1520ID que soporta IRC5+OmniCore).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 910SC', '3HAC056430-001', 'Inspección', 'Ball screw spline unit (ejes 3-4) / Topes mecánicos ejes 1-2 / Correas dentadas (eje 3, eje 4 upper, eje 4 lower) / Arnés / Etiquetas', 'c/100 km (ball screw) / c/12 meses (resto) / Regulary (arnés, robot general)', 'IRC5', 'ROBOT SCARA — SIN amortiguadores, SIN cambio de aceite. Ejes 1-2: gearboxes con grasa (Harmonic Grease 4B No.2, 42g cada uno). Ejes 3-4: NO son gearbox sino BALL SCREW SPLINE UNIT (art. 3HAC056148-001). Intervalo c/100 km: métrica única en BD — inspección ball screw según distancia recorrida. Topes mecánicos: inspección c/12m PERO inmediata si son impactados. Correas dentadas (3 en total): eje 3 recomendada 34N (nueva 31.1-34.2N, usada 21.8-24.9N); eje 4 upper recomendada 37N (nueva 34.5-37.9N, usada 24.1-27.6N); eje 4 lower recomendada 101N (nueva 92.2-101N). Requiere sonic tensiometer para medición.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 910SC', '3HAC056430-001', 'Lubricación', 'Ball screw spline unit (ejes 3-4)', 'Regulary (inspeccionar condición grasa frecuentemente)', 'IRC5', 'Grasa THK AFA (art. 3HAC058096-001 en TRM — no en PM). Aplicación tópica en shaft del ball screw — sin cantidad específica en PM. TRM especifica 4g total para ejes 3/4 combinados. Procedimiento: liberar freno, mover shaft al límite superior, limpiar grasa vieja, aplicar nueva y rellenar ranuras, mover al límite inferior, repetir, mover arriba-abajo para distribuir. Proteger end effector y periféricos por goteo de grasa.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 910SC', '3HAC056430-001', 'Reemplazo', 'Batería SMB', 'Alerta baja (2 meses antes de agotamiento)', 'IRC5', 'Art. 3HAC051036-001 (DIFERENTE a familia principal que usa 3HAC044075-001 — idéntica al IRB 930). Vida batería: 36 meses con robot apagado 2 días/semana, 18 meses si 16h/día. Overhaul: 20.000h (igual que IRB 930).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 910INV', '3HAC068055-001', 'Inspección', 'Ball screw spline unit (ejes 3-4) / Topes mecánicos SOLO eje 3 / Correas dentadas (5 uds) / Arnés / Pintura / Etiquetas / Bellows (solo CleanRoom/IP54)', 'c/12 meses / Regulary (robot general)', 'OmniCore', 'SCARA INVERTIDO (montaje en techo) — único SCARA invertido en BD. DIFERENCIAS clave vs IRB 910SC: sin topes ejes 1-2 (solo eje 3), SIN c/100 km, tiene componente BELLOWS (fuelle) exclusivo para CleanRoom/IP54. 5 CORREAS DENTADAS (vs 3 del 910SC): eje 1, eje 2, eje 3, eje 4, eje 4-2. Tensiones nuevas (N): eje1=100-110, eje2=65-71, eje3=32-36, eje4=38-42, eje4-2=120-132. Bellows (solo CleanRoom/IP54): 350mm=3HAC062062-001 / 550mm=3HAC066917-001. Torque clamps bellow: 0.6Nm ±10%.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 910INV', '3HAC068055-001', 'Lubricación', 'Ball screw spline unit (ejes 3-4)', 'Cuando se detecta degradación de grasa (decoloración/sequedad) o según aplicación', 'OmniCore', 'Grasa THK AFA — 2 gramos total para ejes 3/4 (MENOR que IRB 910SC que usa 4g). Ejes 1 y 2: pre-lubricados de fábrica — "no grease amount available" — NO re-engrasar. Para robots CleanRoom/IP54: retirar bellows primero para acceder al ball screw. Cable harness: FM222 (3HAC029132-001).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 910INV', '3HAC068055-001', 'Reemplazo', 'Batería SMB', 'c/36 meses ó alerta baja', 'OmniCore', 'Art. 3HAC044075-001 (DIFERENTE al 910SC que usa 3HAC051036-001 — idéntica al resto de familia). SMB unit: 3HAC063968-001. OVERHAUL c/20.000h (programado, no "regulary" como 910SC). Gearbox life: 20.000h (uso normal y extremo). Cable harness: 20.000h. Soporta Cyclic Brake Check con opción SafeMove (el 910SC no). Aplicaciones L/H/P (Life science/Healthcare/Pharma) reducen vida útil.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 260', '3HAC026048-001', 'Cambio aceite', 'Eje 6 (wrist)', 'Solo si NO se usa Shell Tivela S150 (con Tivela no hay cambio programado)', 'IRC5', 'PALLETIZER 4 EJES - ejes 1-3 son MAINTENANCE-FREE (lubricated for life). Unico eje con cambio condicional: eje 6 (wrist). Volumenes TRM: E1 XP320 6.400ml, E2 XP320 4.500ml, E3 XP320 3.800ml, E6 TMO150 70ml. WebConfig: TMO150=3HAC032140-001, XP320=11712016-604. Ejes 4 y 5 NO APLICAN.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 260', '3HAC026048-001', 'Inspeccion', 'Cables senal brazo inferior+superior / Etiquetas / Mechanical stop eje 1', 'c/36 meses (cables) / c/12 meses (etiquetas, tope eje 1)', 'IRC5', 'SIN amortiguadores en schedule. SIN disp. equilibrado. Cables de senal: reemplazar si danados. Mechanical stop axis 1: reemplazo c/60 meses (5 anos) si esta doblado.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 260', '3HAC026048-001', 'Reemplazo', 'Bateria SMB', 'c/36 meses (3-pin) o alerta baja (2-pin)', 'IRC5', 'Bateria 3-pin: RMU101=3HAC044168-001 o RMU102=3HAC043904-001 (vida 36 meses). Bateria 2-pin: DSQC633A (reemplazo solo por alerta baja). Overhaul: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 365', '3HAC079185-001', 'Inspeccion', 'Ball bearing cups ejes 4-5 / Slide bearings / Telescopic shafts / Lower arms / Upper arms / Etiquetas', 'c/6 meses (cups visual) / c/12 meses', 'OmniCore', 'DELTA PARALELO FLEXPICKER 5 ejes (3 delta + 2 muneca opcional). Arquitectura especial: lower arms con ball joints + upper arms + telescopic shafts. Inspeccion ball bearing cups: primero visual c/6m, completa c/12m. SIN cambio de aceite (no en TRM). SIN amortiguadores. SIN disp. equilibrado. Torque attachment upper arm: 16Nm con Loctite 2400/243.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 365', '3HAC079185-001', 'Reemplazo', 'Ball bearing cups (ejes 4-5) / Slide bearings (telescopic shafts)', 'c/12 meses o 3800h (cups) / c/12 meses o 3000h (slide bearings) - lo que ocurra primero', 'OmniCore', 'CRITICO: componentes de desgaste rapido comparado con robots articulados. Ball bearing cups: 3800h es muy inferior a intervalos articulados. Slide bearings: 3000h es incluso mas corto. Ambos necesitan reemplazo, no solo inspeccion. Articulos en catalogo externo ABB Robotics One.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 365', '3HAC079185-001', 'Reemplazo', 'Bateria SMB', 'Segun intervalo de mantenimiento o alerta baja', 'OmniCore', 'Art. 3HAC044075-001. Gearbox expected life: 20.000h. Overhaul completo NO explicitamente programado en schedule.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 390', '3HAC066566-001', 'Cambio aceite', 'Reductoras ejes 1, 2, 3', 'c/20.000h DTC', 'IRC5 / OmniCore', 'DELTA PARALELO FOOD GRADE. Volumenes identicos para todas variantes: E1=2.600ml, E2=2.600ml, E3=2.600ml. Aceite: SHC Cibus 220 (FOOD GRADE - unico en BD) - WebConfig 3HAC6450-5. Gearboxes life: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 390', '3HAC066566-001', 'Cambio aceite', 'Eje 4 gear prestage + Delta unit (eje 4) / -10/1300: adicionalmente eje 5 prestage', 'c/12.000h DTC', 'IRC5 / OmniCore', '-15/1300: E4 prestage=105ml + Delta unit (eje 4)=550ml. -10/1300: E4 prestage=105ml + E5 prestage=105ml + Delta unit (ejes 4+5)=750ml. Aceite SHC Cibus 220 (food grade) en toda la maquina.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 390', '3HAC066566-001', 'Lubricacion', 'Telescopic shafts', 'c/8.000h DTC', 'IRC5 / OmniCore', 'Lubricacion especifica de ejes telescopicos - intervalo separado de cambio aceite. Sin tipo de grasa especificado en schedule (referir a procedimiento en PM).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 390', '3HAC066566-001', 'Inspeccion', 'Cups axes 4-5 (visual c/6m + completa c/12m) / Motores axes 1-3 / Telescopic shafts / Lower arms / Etiquetas', 'after first 150h + c/6m + c/12m / c/12m motores (primera) + c/6m despues', 'IRC5 / OmniCore', 'Primera inspeccion motores axes 1-3: a los 12m, luego cada 6m. Cups axes 4-5: primera visual c/6m, luego completa c/12m. Lower arms: inspeccion ball joints y tubos c/12m. Motores life: 12.000h. Universal joints life: 12.000h. Telescopic shaft life: 20.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 390', '3HAC066566-001', 'Reemplazo', 'Universal joint + Telescopic shaft / Motores axes 1-3 / Bateria SMB', 'c/36 meses (joint+shaft) / segun life expectancy (motores) / alerta baja', 'IRC5 / OmniCore', 'Universal joint + telescopic shaft: reemplazo programado c/36m (para evitar fallo en uso). Motores axes 1-3: reemplazo segun life (12.000h). Bateria: 3HAC044075-001. Overhaul completo c/40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 460', '3HAC039842-001', 'Cambio aceite', 'Reductoras ejes 1, 2, 3, 6', '1a cambio c/6.000h DTC; 2a c/20.000h; siguientes c/20.000h', 'IRC5 / OmniCore', 'PALLETIZER 4 EJES (1, 2, 3, 6 - sin eje 4 ni 5). Volumenes TRM: E1 TMO150 5.900ml, E2 TMO150 3.200ml, E3 TMO150 3.200ml, E6 TMO150 300ml. TODOS los ejes usan TMO150 (diferente al IRB 260 que usa XP320 en ejes 1-3). WebConfig 3HAC032140-001. NO MEZCLAR con otros aceites.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 460', '3HAC039842-001', 'Inspeccion', 'Nivel aceite TODOS los ejes (1, 2-3, 6) / Amortiguadores / Arnes / Etiquetas / Tope eje 1', 'c/6 meses (nivel aceite) / c/12 meses (resto)', 'IRC5 / OmniCore', 'Inspeccion nivel aceite c/6 MESES - mas frecuente que IRB 660/760 (c/12m). Amortiguadores (4 tipos): A) lower arm upper (2 uds), B) lower arm lower (2 uds), C) axis 2 (2 uds), D) axis 3 (2 uds). Articulos en catalogo externo. Temp aceite para medicion: +25C +-10C.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 460', '3HAC039842-001', 'Reemplazo', 'Bateria SMB', 'c/36 meses (3-pin) o alerta baja (2-pin)', 'IRC5 / OmniCore', 'Bateria 3-pin: RMU101=3HAC044168-001 / RMU102=3HAC043904-001. Bateria 2-pin: DSQC633A. OVERHAUL: 30.000h (UNICO palletizer con 30.000h - resto familia 40.000h). Gearbox life: 30.000h. Cable harness life: 30.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 660', '3HAC025755-001', 'Cambio aceite', 'Reductoras ejes 1, 2, 3, 6', '1a cambio c/6.000h DTC; 2a c/24.000h; siguientes c/24.000h', 'IRC5 / OmniCore', 'PALLETIZER 4 EJES (1, 2, 3, 6). Intervalo siguientes 24.000h (vs 20.000h en IRB 460). Volumenes TRM: E1 TMO150 8.000ml, E2 TMO150 5.000ml, E3 TMO150 5.000ml, E6 TMO150 300ml. Volumenes mas altos que IRB 460 (para 4 ejes mas grandes). WebConfig 3HAC032140-001. NO MEZCLAR con otros aceites.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 660', '3HAC025755-001', 'Inspeccion', 'Nivel aceite ejes 1, 2-3, 6 / Disp. equilibrado / Amortiguadores / Arnes / Etiquetas / Tope eje 1', 'c/12 meses', 'IRC5 / OmniCore', 'Inspeccion nivel aceite c/12 meses (vs IRB 460 c/6m). Amortiguadores (4 tipos): A) lower arm upper (2 uds), B) lower arm lower (1 PC - diferencia vs IRB 460 que son 2), C) axis 2 (2 uds), D) axis 3 (2 uds). Articulos en catalogo externo.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 660', '3HAC025755-001', 'Lubricacion', 'Rodamientos disp. equilibrado + piston rod', 'c/12.000h DTC (rodamientos) / segun inspeccion (piston rod)', 'IRC5 / OmniCore', 'Rodamientos: Tribol GR100-2PD (art. 3HAC9408-1). Herramienta lubricacion especifica: 3HAC5222-2 (diferente a IRB 760 que usa 3HAC039296-001). Piston rod grease: Shell SRS Grease 4000 / Preem Novatex Heavy EP2 / Castrol Entrepenadfett / Statoil Uniway 2X2N. Loctite 2400 (o equivalente 243). Procedimiento: quitar locknut, montar herramienta lubricacion, aplicar grasa hasta que salga limpia por sellado interior.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 660', '3HAC025755-001', 'Reemplazo', 'Bateria SMB', 'c/36 meses (3-pin) o alerta baja (2-pin)', 'IRC5 / OmniCore', 'Bateria 3-pin: RMU101=3HAC044168-001 / RMU102=3HAC043904-001. Bateria 2-pin: DSQC. Overhaul: 40.000h. Balancing device life: 40.000h. Gearboxes life: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 760', '3HAC039838-001', 'Cambio aceite', 'Reductoras ejes 1, 2, 3, 6', '1a cambio c/6.000h DTC; 2a c/24.000h; siguientes c/24.000h', 'IRC5 / OmniCore', 'PALLETIZER 4 EJES - volumenes casi identicos a IRB 660 excepto eje 6. Volumenes TRM: E1 TMO150 8.000ml, E2 TMO150 5.000ml, E3 TMO150 5.000ml, E6 TMO150 850ml (DIFERENCIA CLAVE: vs IRB 660 E6=300ml). WebConfig 3HAC032140-001.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 760', '3HAC039838-001', 'Inspeccion', 'Nivel aceite ejes 1, 2-3, 6 / Disp. equilibrado / Amortiguadores / Arnes / Etiquetas / Tope eje 1 / Tope eje 3 (SOLO variante -445/3.2)', 'c/12 meses', 'IRC5 / OmniCore', 'Inspeccion nivel c/12m. Tope mecanico eje 3: EXCLUSIVO para variante -445/3.2 (inspeccion c/12m). La variante -450/3.2 NO tiene tope adicional eje 3. Amortiguadores: estructura similar a IRB 660.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 760', '3HAC039838-001', 'Lubricacion', 'Rodamientos disp. equilibrado + PISTON ROD (diferencia vs IRB 660)', 'c/12.000h DTC', 'IRC5 / OmniCore', 'Rodamientos: Tribol GR100-2PD (art. 3HAC9408-1). HERRAMIENTA LUBRICACION: 3HAC039296-001 (DIFERENTE a IRB 660 que usa 3HAC5222-2). Piston rod grease: Shell SRS Grease 4000 / Preem Novatex Heavy EP2 / Castrol Entrepenadfett / Statoil Uniway 2X2N. IMPORTANTE: el IRB 760 lubrica bearings Y piston rod (IRB 660 solo bearings en schedule).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 760', '3HAC039838-001', 'Reemplazo', 'Bateria SMB', 'c/36 meses (3-pin) o alerta baja (2-pin)', 'IRC5 / OmniCore', 'Bateria 3-pin: RMU101=3HAC044168-001 / RMU102=3HAC043904-001. Bateria 2-pin: DSQC. Overhaul: 40.000h. Balancing device life: 40.000h. Gearboxes life: 40.000h.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 940', '3HAC 022034-001', 'Mantenimiento diario', 'Robot completo', 'Diario', 'M2000 / M2004', 'TRICEPT - arquitectura paralela unica en BD (3 actuadores lineales, no ejes rotatorios). Procedimiento diario: limpieza, check safety equipment, inspeccion visual cables/mangueras, verificar niveles fluidos, comprobar presiones/flujos. SIN uso de aire comprimido para limpieza (riesgo de contaminacion).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 940', '3HAC 022034-001', 'Lubricacion', 'Linear bearings (2 uds)', 'c/1.000h (intervalo muy corto - condiciones normales)', 'M2000 / M2004', 'Grasa: Kluber Isoflex NBU 15 - 2x4ml por bearing (total 8ml por bearing). Toolkit: 3HAC 020925-001 (incluye grasa). Procedimiento: limpiar rails, aplicar 4ml por nipple inferior, mover robot direccion X varias veces, aplicar otros 4ml. AMBOS lados deben lubricarse. ADVERTENCIA: extremos del linear bearing son de plastico - pueden romperse si no se aplica con cuidado. Intervalo puede ser MAS CORTO en condiciones severas (alta temperatura, polvo abrasivo/absorbente).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 940', '3HAC 022034-001', 'Lubricacion', 'Actuators (3 uds)', 'c/1.000h (intervalo muy corto)', 'M2000 / M2004', 'Grasa: Kluberplex BEM 34-132 - 2x4ml por actuator. CADA actuator tiene 4 grease nipples - usar el que mira HACIA ARRIBA para que la grasa caiga sobre el lead screw. Procedimiento: extender actuator a maximo, aplicar 4ml, mover a todo recorrido varias veces, aplicar otros 4ml. CRITICO: el actuator DEBE estar extendido antes de lubricar para aplicacion correcta en lead screw.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 940', '3HAC 022034-001', 'Reemplazo', 'Filtro sistema sobrepresion / Bateria SMB distribution box / Cable espiral', 'c/12m (filtro) / c/12-36m (bateria) / c/48m (cable espiral)', 'M2000 / M2004', 'Filtro: art. 3HAC 17158-1. Tras cambio filtro: ajustar sistema sobrepresion. Bateria en DISTRIBUTION BOX separada - vida 12-36 meses variable segun uso. Cable espiral: reemplazo programado c/48 meses (4 anos). SIN gearbox oil. SIN amortiguadores. SIN correas dentadas. SIN disp. equilibrado clasico.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6620', '3HAC027151-001', 'Cambio aceite', 'Reductoras ejes 1, 2, 3, 6', '1a cambio c/6.000h DTC; 2a c/24.000h; siguientes c/24.000h', 'M2004', 'IRB 6620-150/2.2 (880 kg). Ejes 1-3 y 6 con cambio diferenciado. Aceite: Kyodo Yushi TMO 150 (WebConfig 3HAC032140-001). Volumenes TRM: E1 ~6l, E2 ~4l, E3 ~2l. E6 protection Standard ~0.3l / Foundry Plus ~0.4l (importante: la version Foundry Plus usa mayor volumen en eje 6). NO MEZCLAR con otros aceites.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6620', '3HAC027151-001', 'Cambio aceite', 'Reductoras ejes 4, 5', 'c/24.000h DTC (sin primer cambio anticipado)', 'M2004', 'Aceite: Mobilgear 600 XP 320/XMP 320 (WebConfig 11712016-604). Volumenes TRM: E4 ~5.5l, E5 ~3l. NOTA: si el robot opera a temperatura ambiente > 50C, el mantenimiento puede requerir mayor frecuencia.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6620', '3HAC027151-001', 'Inspeccion', 'Nivel aceite todos los ejes (1-6) / Amortiguadores ejes 2, 3, 5 / Arnes / Etiquetas / Tope mecanico eje 1 (opcion: eje 1 y 3)', 'c/12 meses', 'M2004', 'Inspeccion nivel aceite en los 6 ejes cada 12m. Amortiguadores (3 tipos): eje 2 y eje 3 = 3HAC12320-1 (identico articulo para ambos ejes), eje 5 = 3HAC024541-001. NOTA: articulo damper eje 5 es DIFERENTE al usado en IRB 67xx (3HAC054956-001) - especifico de IRB 6620. Opcion: con kit mechanical stop axes 1 y 3 inspeccion c/12m.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6620', '3HAC027151-001', 'Reemplazo', 'Bateria SMB', 'Alerta baja', 'M2004', 'Bateria SMB lithium. Vida bateria nueva: 36 meses con robot apagado 2 dias/semana, 18 meses si apagado 16h/dia. Se puede extender ~3x con battery shutdown service routine. Overhaul robot: 40.000h. Gearboxes life: 40.000h. Cable harness life: 40.000h (uso normal) / 20.000h (uso extremo).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6620LX', '3HAC025861-001 (Product Spec) + TRM', 'Cambio aceite', 'Reductora eje 1 (CRITICO: aceite DIFERENTE)', 'Segun schedule base IRB 6620 (PM especifico 3HAC035737-001 no disponible)', 'M2004', 'IRB 6620LX-150/1.9 (610 kg) - variante LINEAR EXTENDED (montado sobre eje lineal). EJE 1 USA MOBIL GLYGOYL 460 ~7l - UNICO ROBOT EN BD CON ESTE ACEITE (no TMO150). Glygoyl es un aceite sintetico PAG para engranajes sin-fin. Volumenes TRM sin WebConfig especificado. ADVERTENCIA CRITICA: NO mezclar Glygoyl 460 con TMO150 o XP320 de otros ejes.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6620LX', '3HAC025861-001 (Product Spec) + TRM', 'Cambio aceite', 'Reductoras ejes 2, 3, 6', 'Segun schedule base IRB 6620', 'M2004', 'Kyodo Yushi TMO 150 (3HAC032140-001). Volumenes TRM: E2 ~4l, E3 ~2l, E6 ~0.4l. E6 MAYOR que IRB 6620 Standard (0.3l) - identico a IRB 6620 Foundry Plus.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6620LX', '3HAC025861-001 (Product Spec) + TRM', 'Cambio aceite', 'Reductoras ejes 4, 5', 'Segun schedule base IRB 6620', 'M2004', 'Mobilgear 600 XP 320/XMP 320 (11712016-604). Volumenes TRM: E4 ~5.5l, E5 ~3l. Identicos al IRB 6620 Standard.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6620LX', '3HAC025861-001 (Product Spec) + TRM', 'Inspeccion', 'Nivel aceite todos los ejes / Eje lineal asociado / Amortiguadores', 'c/12 meses (asumido segun schedule 6620)', 'M2004', 'Robot DEBE montarse sobre eje lineal segun spec: "IRB 6620LX must be mounted together with a Linear Axis, see Product Specification 3HAC036094-001". Mantenimiento del eje lineal se documenta por separado. Schedule interno igual al IRB 6620. Amortiguadores: asumidos iguales a IRB 6620 (3HAC12320-1 ejes 2-3, 3HAC024541-001 eje 5) - verificar en PM especifico 3HAC035737-001 si esta disponible.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 3400', '3HAB 0009-37 (M94A Rev.2)', 'Lubricacion', 'Large diameter bearing axis 1', 'c/1 ano o c/2000h (lo que ocurra primero)', 'S4 (M94A)', 'Legacy 1994. ESSO Beacon EP 2 o equivalente (ABB art. 1171 4013-301, quality 7 1401-301). Equivalentes: Shell Alvania EP Grease, SKF Grease LGEP 2, BP Energrease LS-EP. Minimo 25 gramos por nipple (2 nipples). Eje 1 debe rotarse +-90 durante lubricacion. Aplicar hasta que salga grasa por sello de goma.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 3400', '3HAB 0009-37 (M94A Rev.2)', 'Gearboxes', 'Ejes 1, 2, 3 (gearboxes con GRASA LIQUIDA)', 'LUBRICATED FOR LIFE (sin cambio programado)', 'S4 (M94A)', 'Ejes 1-3 usan GRASA LIQUIDA (no aceite) - lubricados de por vida. Grasa liquida: ABB art. 1171 4016-611 = BP Energrease LS-EP00. Cantidades (floor-mounted): Eje 1 = 7.3 kg (8.4 L / 2.22 US gal), Eje 2 = 4.5 kg (5.2 L / 1.37 US gal), Eje 3 = 4.5 kg (5.2 L / 1.37 US gal). Solo requieren inspeccion visual de nivel.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 3400', '3HAB 0009-37 (M94A Rev.2)', 'Cambio aceite', 'Ejes 4, 5, 6 (gears con ACEITE)', '1a cambio c/2000h o 1 ano; siguientes c/5 anos', 'S4 (M94A)', 'Variante IRB 3400 (F) / 1.95-30: eje 4 ~1 L, ejes 5+6 total 1.2 L (0.6 L cada lado). Variante IRB 3400 / 2.5-10: ejes 5+6 solo 0.50 L total. Aceite: ABB 1171 2016-604 = BP Energol GR-XP 320 / Castrol Alpha SP 320 / Esso Spartan EP 320 / Kluber Lamora 320 / Optimol Optigear 5180 / Shell Omala Oil 320 / Texaco Meropa 320 / Statoil Loadway EP. Magnetic drain plugs: limpiar durante cambio.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 3400', '3HAB 0009-37 (M94A Rev.2)', 'Inspeccion', 'Mechanical stop eje 1 / Sistema balancing (presion N2) / Cable base', 'Regular / c/1 ano o c/2000h (balancing)', 'S4 (M94A)', 'Mechanical stop eje 1: verificar que el pin no este doblado. Si se dobla tras impacto: reemplazar. Art. Standard: 2196 065-47. Art. Foundry: 3HAA 2559-1. Cable base: ~4 millones de ciclos. BALANCING SYSTEM con nitrogeno (N2): control c/1 ano o 2000h. Presion variable con temperatura ambiente. Oil level en drain tank < 10mm. Requiere analisis especifico en Repair section.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 3400', '3HAB 0009-37 (M94A Rev.2)', 'Reemplazo', 'Bateria measuring system / Bateria memory back-up (x2) / Filtro cooling', 'c/3 anos (bateria medicion) / Segun expiracion (memory) / Variable (filtro)', 'S4 (M94A)', 'Bateria measuring system: art 4944 026-4 (Rechargeable Ni-Cd, 7.0-8.7V, tiempo recarga 18h). Debajo de gearbox cover eje 2. Bateria memory back-up (2 unidades): art 3HAB 2038-1 en rack cerca del main computer board. Filtro cooling device: art 7820 004-3 - intervalo depende del entorno (taller dusty = mas frecuente). Extra dust filter suministrado con robot.');
INSERT INTO `actividades_mantenimiento` (fabricante_id, familia_robot, documento, tipo_actividad, componente, intervalo_estandar, intervalo_foundry, notas) VALUES
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6400S', '3HAC 10222-1 (M2000)', 'Lubricacion', 'Large diameter bearing eje 1', 'Foundry o movimientos grandes >=+-45 eje 1 (grease change)', 'M2000', 'Variante S = Shelf/Suspended (invertida/estanteria). 2 variantes BD. Grasa: ABB 1171 4013-301 = ESSO Beacon EP 2 / Shell Alvanina EP Grease / SKF Grease LGEP 2 / BP Energrease LS-EP 2. Para foundry robots: Shell Retinax MS. Turn eje 1 +90 durante lubricacion hasta que exuda nueva grasa por sello de goma.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6400S', '3HAC 10222-1 (M2000)', 'Cambio grasa', 'Gearboxes ejes 1 y 6 (GRASA - no aceite)', 'PRESS-TENDING: eje 1 entre 6.000-12.000h segun cycle time; eje 6 entre 4.000-12.000h segun Ja6', 'M2000', 'Ejes 1 y 6: GRASA (no aceite). Intervalo VARIABLE segun aplicacion. Para PRESS-TENDING (Option 51 PT adaptation IRB6400/2.8-120) y HEAVY DUTY eje 1 (option 5x instalada): intervalo decrece con cycle time menor. Eje 1: cycle 6.5s=12.000h, cycle 4s=6.000h (grafico Figure 1 PM). Eje 6: Ja6=50 kgm2->12.000h, Ja6=120 kgm2->4.000h. Volumen eje 1: 1.3 L (fresh) / ~3.0 L (change operation). Grasa: Optimol Longtime PD 0 (ABB 3HAA 1001-294) o Teijin Seiki Molywithe (ABB 3HAC 2331-1).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6400S', '3HAC 10222-1 (M2000)', 'Cambio grasa', 'Gearboxes ejes 2 y 3 (GRASA - no aceite)', 'Segun inspeccion nivel (no interval fijo en tabla)', 'M2000', 'Ejes 2 y 3: GRASA (no aceite). Volumen: 1.2 L (fresh) / ~2.0 L (change). Grasa: Teijin Seiki Molywithe (ABB 3HAC 2331-1). CRITICO: drain plug debe estar abierto durante lubricacion para evitar overpressure. Mover ejes lentamente hacia adelante/atras durante lubricacion. Continuar hasta que nueva grasa exude por drain hole.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6400S', '3HAC 10222-1 (M2000)', 'Cambio aceite', 'Gearboxes ejes 4 y 5', 'Cambio aceite segun inspeccion nivel + tabla intervalos', 'M2000', 'Ejes 4 y 5: ACEITE (no grasa). Volumen aprox: 6 L por gearbox (6.5 L para variante 2.4-200 FHD). Aceite: ABB 1171 2016-604. Equivalentes: BP Energol GR-XP 320, Castrol Alpha SP 320, Esso Spartan EP 320, Kluber Lamora 320, Mobil Mobilgear 632, Optimol Optigear 5180, Shell Omala Oil 320, Texaco Meropa 320, Statoil Loadway EP. Eje 4: drenar por hole A, rellenar hole B hasta borde inferior. Eje 5: rotar eje 4 manualmente +-90 para drenaje/llenado.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6400S', '3HAC 10222-1 (M2000)', 'Lubricacion', 'Balancing unit axis 2 (bearings + piston rod)', 'Bearings: inspeccion+grease c/12.000h; Piston rod: periodica c/2 anos', 'M2000', 'Bearings balancing unit eje 2: c/12.000h - inspeccionar Y lubricar. Herramienta lubricacion: 3HAC 4701-1. Aux shafts: upper=3HAB 6558-1, lower=3HAB 6567-1. Torque KM nuts: 50-60 Nm con Loctite 243. Check play min 0.1mm entre support washer y bearing seat. Piston rod: verificar guiding ring (art. 3HAB 6176-1), lubricar periodicamente. Grasa piston rod: Castrol Spheerol SX2 / Shell 1352 CA EP2 / OK Super Grease L2 / Statoil Uniway 2X2N.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6400S', '3HAC 10222-1 (M2000)', 'Inspeccion + reemplazo', 'Mechanical stop eje 1 / Cabling visible / Accumulator measuring system / Cooling filter eje 1', 'Check 1-2x/ano (cable, stop) / c/3 anos (accumulator) / Variable (filter)', 'M2000', 'Inspeccion cabling visible: 1-2x/ano, cambiar si danado. Life base cable: 4 millones de ciclos. Mechanical stop eje 1: check que no este doblado - reemplazar si deformado o danado. Accumulator measuring system: c/3 anos (variable segun uso). Cooling motor eje 1 filter: cambio segun ambiente (dusty = mas frecuente).'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6790', '3HAC063331-001', 'Cambio aceite', 'Reductoras ejes 1, 2, 3, 6 (con analisis agua)', 'c/20.000h DTC si water<1.5 vol%; ANTES si water content mayor (ver notas)', 'IRC5 / OmniCore', 'FOUNDRY PRIME - disenado para aplicaciones de lavado con productos quimicos. UNICO robot BD con analisis de contenido de agua en aceite (ejes 1,2,3,6). Volumenes TRM: E1 TMO150 ~3.5l, E2 TMO150 ~3.5l, E3 TMO150 ~2.5l, E6 TMO150 ~0.5l (WebConfig 3HAC032140-001). REGLAS AGUA: 0-1.5 vol%=medir de nuevo c/12m; 1.5-2 vol%=cambiar en 12m; >2 vol%=cambiar en 6m; >3 vol%=REEMPLAZAR gearbox. Si water<1.5% estable: cambio c/20.000h. O-ring oil plug G1/2: 3HAC061327-059 (REEMPLAZAR siempre tras cambio). Torque plug: 24Nm. Temp aceite medicion: +25C +-10C. Nivel eje 1: 58mm +-5mm bajo sealing surface.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6790', '3HAC063331-001', 'Cambio aceite', 'Reductoras ejes 4, 5 (SIN analisis agua)', 'c/18 meses (calendar) o c/12.000h DTC', 'IRC5 / OmniCore', 'Ejes 4 y 5: cambio periodico c/18 meses - NO requieren analisis de agua. Aceite: Mobilgear 600 XP320/XMP320 (WebConfig 11712016-604). Volumenes TRM: E4 ~7l, E5 ~3.5l.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6790', '3HAC063331-001', 'Inspeccion', 'Nivel aceite / Balancing device / Arnes / Velcro straps / Dampers ejes 2-3 / Mechanical stop / Surface treatment / Overpressure system', 'c/12 meses (mayoria) / c/6 meses (airtightness R1.MP)', 'IRC5 / OmniCore', 'Multiples inspecciones c/12m incluyendo sistema de SOBREPRESION (Foundry Prime). Airtightness test power connector R1.MP: c/6 meses (critico para mantener overpressure). Verificar cubiertas: motor ejes 1, 2, 3, 4, 6, bateria, balancing device, wrist housing. Flow sensor: valor >1.5 l/min indica bloqueo o fuga. Dampers ejes 2 y 3 (2 pcs cada uno) - articulos en catalogo externo IRB 6700/6700Inv (compartidos). Loctite 2400 (o 243) en attachment screws M6x60. Inspeccion de nickel coating (pintura especial FoundryPrime) - retocar si danada.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6790', '3HAC063331-001', 'Analisis agua en aceite', 'Contenido de agua ejes 1, 2, 3, 6', 'c/12 meses', 'IRC5 / OmniCore', 'ACTIVIDAD EXCLUSIVA FoundryPrime. Medir water content en oil al cambiar aceite Y c/12m. Realizar tambien inspeccion de oil level. Categorias de accion: 0-1.5 vol%=remedir 12m; 1.5-2 vol%=cambio en 12m; >2 vol%=cambio en 6m; >3 vol%=REEMPLAZAR GEARBOX completo.'),
((SELECT id FROM fabricantes WHERE nombre='ABB'), 'IRB 6790', '3HAC063331-001', 'Reemplazo', 'Desiccant bag (absorbedor humedad) / Bateria SMB / Gasket SMB/BU', 'c/24 meses (asumido segun schedule) / Intervalo mantenimiento o alerta baja / Si danado', 'IRC5 / OmniCore', 'Desiccant bag: art 3HAC080620-001 (unico en BD - absorbedor de humedad en SMB/BU recess, criticoFoundryPrime). Gasket SMB: 3HAC044074-002 (reemplazar si danado). Stainless steel fasteners en todo el robot (especifico FoundryPrime). Bateria: 3HAC044075-001 (familia estandar). Overhaul: 40.000h. Gearboxes life: 40.000h. Balancing device life: 40.000h (variable en aplicaciones L/H/P).');
